VALUES
  ('bookkeeper-moex-02099', 'bookkeeper', 'bookkeeper-moex-099-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依記帳士法關於記帳士懲戒之規定，下列敘述何者正確？', '["被付懲戒之記帳士對於懲戒覆審委員會之決議，於法律規定期限內提起行政訴訟者，其處分決議尚未 確定", "記帳士懲戒委員會組織，由法務部訂之", "被懲戒人可依記帳士法第31條規定期限30日內，向記帳士懲戒覆審委員會請求覆審", "記帳士受懲戒處分確定後，通知記帳士公會，並於網站公告即可"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "81d3ec551896", "answer_pdf_sha1": "452e806b995e", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-02100', 'bookkeeper', 'bookkeeper-moex-099-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '張三記帳士因違反商業會計法第76條之規定，受主管機關處新臺幣二十萬元之罰鍰確定，其情節重大， 足以影響記帳士信譽，應交付那一組織懲戒？', '["經濟部", "記帳士懲戒委員會", "財政部", "一事不二罰，不得再交付懲戒"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "81d3ec551896", "answer_pdf_sha1": "452e806b995e", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-02101', 'bookkeeper', 'bookkeeper-moex-099-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依記帳士法規定，記帳士有下列那一項行為時，應交付懲戒？①因業務之犯罪行為經移送法辦者  ②因', '["逃漏稅捐經國稅局處分有案者", "未經委任人許可， 洩漏業務上之秘密  ⑤違反記帳士公會章程之規定，情節重大者", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "81d3ec551896", "answer_pdf_sha1": "452e806b995e", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-02102', 'bookkeeper', 'bookkeeper-moex-099-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依記帳士法關於記帳士公會規定，下列敘述何者錯誤？', '["同一直轄市或縣市只能成立一個記帳士公會", "各縣市記帳士公會不得拒絕具有會員資格者加入", "記帳士欲開業執行業務，則加入各縣市記帳士公會為強制性規定", "各縣市記帳士公會，應由該行政區域內已登錄記帳士二十人以上發起組織之"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "81d3ec551896", "answer_pdf_sha1": "452e806b995e", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-02103', 'bookkeeper', 'bookkeeper-moex-099-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依記帳士法規定，記帳士欲在登記開業區域以外之其他縣市執行業務時，應如何辦理？', '["向其它縣市國稅分局登記，並設分事務所", "向財政部登記，免設分事務所", "執行業務範圍以其委任人所在地縣市為限，向財政部登記，並設分事務所", "向其它縣市政府登記，免設分事務所"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "81d3ec551896", "answer_pdf_sha1": "452e806b995e", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-02104', 'bookkeeper', 'bookkeeper-moex-099-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依記帳士法規定，關於主管機關記帳士名簿，下列敘述何者正確？', '["委任人委任日期，為主管機關記帳士名簿應載明事項之一", "尚未登錄之記帳士，其地址如有變更時，應向主管機關申請變更", "主管機關應備置記帳士名簿，其應保存期限至少五年", "記帳士曾否受過懲戒，為主管機關記帳士名簿應載明事項之一"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "81d3ec551896", "answer_pdf_sha1": "452e806b995e", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-02105', 'bookkeeper', 'bookkeeper-moex-099-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '歸榮商號地址設於臺南市，其商業會計事務之主管機關應為：', '["臺南市政府", "臺南市商業同業公會", "經濟部", "財政部南區國稅局臺南市分局"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "81d3ec551896", "answer_pdf_sha1": "452e806b995e", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-02106', 'bookkeeper', 'bookkeeper-moex-099-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依記帳士法規定，欲充任我國記帳士者，下列規定何者錯誤？', '["外國人得依中華民國法令取得記帳士證書，充任記帳士", "受破產之宣告尚未復權者，不得充任記帳士", "具有中華民國國籍為取得記帳士資格之必要條件", "受監護或輔助之宣告尚未撤銷者，不得充任記帳士"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "81d3ec551896", "answer_pdf_sha1": "452e806b995e", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-02107', 'bookkeeper', 'bookkeeper-moex-099-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '台榮有限公司為新設立，其會計人員之設置，依商業會計法之規定，下列敘述何者正確？', '["其會計人員之聘任程序，應有全體股東過半數之同意", "其主辦會計人員之聘任程序，由總經理提報經董事會同意即可", "其主辦會計人員之聘任程序，應由董事會以董事過半數之出席，及出席董事過半數之同意", "如擬委外由記帳士處理會計事務，則應有全體股東過半數之同意"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "81d3ec551896", "answer_pdf_sha1": "452e806b995e", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-02108', 'bookkeeper', 'bookkeeper-moex-099-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '商業會計法關於商業會計記帳之規定，下列敘述何者錯誤？', '["商業會計之記載，除記帳數字適用阿拉伯字外，應以我國文字為之", "因業務需要，而以外國貨幣記帳者，仍應在其決算表中，將外國貨幣折合新臺幣", "外國在臺分公司不可以外幣記帳", "本國公司以外國貨幣交易者，得以外國貨幣記帳"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "81d3ec551896", "answer_pdf_sha1": "452e806b995e", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL)
